tongue_caches.typescript:
function cosine(a: number[], b: number[]): number {
    let dot = 0;
    for (let i = 0; i < a.length; i++) dot += a[i] * b[i];
    const na = Math.sqrt(a.reduce((s, v) => s + v * v, 0)) || 1.0;
    const nb = Math.sqrt(b.reduce((s, v) => s + v * v, 0)) || 1.0;
    return dot / (na * nb);
}

